#!/usr/bin/env node

/**
 * Collect and compare benchmarks between the current branch and a base branch (default: master).
 *
 * Usage:
 *   node collect-benchmarks.mjs [base-branch]
 *
 * What it does:
 *   1. Runs benchmarks on the current branch for each package in PACKAGES
 *   2. Stashes local changes, checks out the base branch, runs benchmarks there
 *   3. Restores the original branch and stashed changes
 *   4. Generates a side-by-side markdown comparison with % change
 *   5. Writes the report to benchmark-report.md at the repo root
 *
 * In GitHub Actions, also sets step outputs for each benchmark result
 * (e.g. dbml-parse-25k-interpret=2856.92).
 */

import fs from "node:fs";
import path from "node:path";
import { execSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { MarkdownTable } from "./utils/markdownTable.mjs";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PACKAGES = ["dbml-parse"];
const ROOT = path.join(__dirname, "../../..");
const TMP_DIR = path.join(ROOT, ".tmp-bench");

function main() {
  const baseBranch = process.argv[2] || "master";
  const commitSha =
    process.env.GITHUB_SHA ||
    execSync("git rev-parse HEAD", { cwd: ROOT, encoding: "utf8" }).trim();

  // Step 1: Run benchmarks on the current branch
  console.log("Running benchmarks on current branch...");
  const currentReports = {};
  for (const pkg of PACKAGES) {
    console.log(`Running benchmarks for ${pkg}...`);
    execSync("npx tsx __benchmarks__/compiler.benchmark.ts", {
      cwd: packageDirectory(pkg),
      stdio: "inherit",
    });
    currentReports[pkg] = readBenchReport(pkg);
  }

  // Step 2: Run benchmarks on the base branch for comparison
  console.log(`\nRunning benchmarks on ${baseBranch}...`);
  const baselineReports = runBenchForBranch(baseBranch);

  // Step 3: Generate and write the comparison report
  console.log("\nGenerating comparison report...");
  const markdown = generateComparisonReport(
    currentReports,
    baselineReports,
    commitSha.substring(0, 8),
    baseBranch,
  );

  const reportPath = path.join(ROOT, "benchmark-report.md");
  fs.writeFileSync(reportPath, markdown);
  console.log(`\nBenchmark report written to: ${reportPath}`);

  console.log("\n" + markdown);
}

main();

// Path helpers

function packageDirectory(packageName) {
  return path.join(ROOT, "packages", packageName);
}

function benchDirectory(packageName) {
  return path.join(packageDirectory(packageName), "__benchmarks__");
}

function tmpBenchDirectory(packageName) {
  return path.join(TMP_DIR, packageName);
}

// Helpers

/**
 * Read the bench.json report generated by compiler.benchmark.ts for a package.
 * Returns null if not found.
 */
function readBenchReport(packageName) {
  const reportPath = path.join(
    benchDirectory(packageName),
    "output/bench.json",
  );

  if (!fs.existsSync(reportPath)) {
    console.error(`Warning: No benchmark results found for ${packageName}`);
    return null;
  }

  return JSON.parse(fs.readFileSync(reportPath, "utf8"));
}

/**
 * Checkout a different branch, run benchmarks there, then restore the original branch.
 * Copies benchmark files to a temp dir before switching so the base branch
 * doesn't need to have them.
 */
function runBenchForBranch(branch) {
  const currentBranch = execSync("git rev-parse --abbrev-ref HEAD", {
    cwd: ROOT,
    encoding: "utf8",
  }).trim();

  // Copy benchmark files to a temp dir so they survive the branch switch
  for (const pkg of PACKAGES) {
    execSync(
      `mkdir -p '${tmpBenchDirectory(pkg)}' && cp -r '${benchDirectory(pkg)}/.' '${tmpBenchDirectory(pkg)}/'`,
      { cwd: ROOT },
    );
  }

  const stashed = execSync("git stash", { cwd: ROOT, encoding: "utf8" }).trim();
  const didStash = !stashed.includes("No local changes");

  try {
    console.log(`Checking out ${branch}...`);
    execSync(`git checkout ${branch}`, { cwd: ROOT, stdio: "inherit" });

    // Restore benchmark files onto the base branch
    for (const pkg of PACKAGES) {
      execSync(
        `mkdir -p '${benchDirectory(pkg)}' && cp -r '${tmpBenchDirectory(pkg)}/.' '${benchDirectory(pkg)}/'`,
        { cwd: ROOT },
      );
    }

    const reports = {};
    for (const pkg of PACKAGES) {
      console.log(`Running benchmarks for ${pkg} on ${branch}...`);
      execSync("npx tsx __benchmarks__/compiler.benchmark.ts", {
        cwd: packageDirectory(pkg),
        stdio: "inherit",
      });
      reports[pkg] = readBenchReport(pkg);
    }

    return reports;
  } finally {
    // Always restore the original branch, even if benchmarks fail
    console.log(`Checking out ${currentBranch}...`);
    execSync(`git checkout ${currentBranch}`, { cwd: ROOT, stdio: "inherit" });
    if (didStash) {
      execSync("git stash pop", { cwd: ROOT, stdio: "inherit" });
    }
    execSync(`rm -rf '${TMP_DIR}'`, { cwd: ROOT });
  }
}

/** Format a bench result as '123.456ms ±1.23%' */
function formatMs(v) {
  return `${v.ms}ms \u00b1${Math.round(v.error * 10000) / 100}%`;
}

/** Compute the % change between current and baseline with an icon (🟢 faster, 🔴 slower, ⚪ similar) */
function formatChange(current, baseline) {
  if (!baseline || !current) return "";
  const pct = ((current.ms - baseline.ms) / baseline.ms) * 100;
  const sign = pct >= 0 ? "+" : "";
  const icon = pct <= -5 ? "🟢" : pct >= 5 ? "🔴" : "⚪";
  return `${icon} ${sign}${pct.toFixed(0)}%`;
}

/**
 * Generate a markdown report comparing current vs baseline results.
 * Each operation gets three columns: current value, baseline value, and % change.
 */
function generateComparisonReport(
  currentReports,
  baselineReports,
  commitSha,
  baseBranch,
) {
  let markdown = `## Benchmark Comparison\n\n`;
  markdown += `**Commit:** ${commitSha} vs **${baseBranch}**\n\n`;

  for (const pkg of PACKAGES) {
    const current = currentReports[pkg];
    const baseline = baselineReports[pkg];
    if (!current) continue;

    const operations = current.operations;
    markdown += `### ${pkg}\n\n`;

    // Build table: suite | 🏠 base (op) | 🔀 PR (op) | change | ...
    const headerCells = ["suite"];
    const alignCells = ["l"];
    for (const op of operations) {
      headerCells.push(`🏠 ${baseBranch} (${op})`, `🔀 PR (${op})`, "change");
      alignCells.push("r", "r", "r");
    }

    const table = new MarkdownTable().headers(headerCells).align(alignCells);

    // Merge suite names from both reports in case they differ
    const allSuites = new Set([
      ...Object.keys(current.suites),
      ...(baseline ? Object.keys(baseline.suites) : []),
    ]);

    for (const suite of allSuites) {
      const cells = [suite];
      for (const op of operations) {
        const cur = current.suites[suite]?.[op];
        const base = baseline?.suites[suite]?.[op];
        cells.push(
          base ? formatMs(base) : "N/A",
          cur ? formatMs(cur) : "N/A",
          cur && base ? formatChange(cur, base) : "",
        );
      }
      table.row(cells);
    }

    markdown += table.build() + "\n\n";
  }

  // Write individual results as GitHub Actions step outputs for downstream use
  if (process.env.GITHUB_OUTPUT) {
    for (const pkg of PACKAGES) {
      const current = currentReports[pkg];
      if (!current) continue;
      for (const [suite, results] of Object.entries(current.suites)) {
        for (const [op, v] of Object.entries(results)) {
          const key = `${pkg}-${suite}-${op}`;
          fs.appendFileSync(process.env.GITHUB_OUTPUT, `${key}=${v.ms}\n`);
        }
      }
    }
  }

  return markdown;
}
